const DOMAIN = 'https://omniwebkit.com';
const BRAND = 'OmniWebKit';

// Helper to build full SEO object from compact input
function s(slug, title, desc, keywords, faq, howToSteps, features, content) {
    return {
        slug, name: title.split('–')[0].trim(),
        title: `${title} | ${BRAND}`,
        description: desc,
        keywords: keywords,
        canonical: `${DOMAIN}/tools/${slug}`,
        faq: faq || [],
        howTo: howToSteps ? { title: `How to Use Our ${title.split('–')[0].trim()}`, steps: howToSteps } : null,
        features: features || [],
        content: content || [],
    };
}

